function loadSavedUrl() {
  const savedUrl = localStorage.getItem("savedUrl");
  if (savedUrl) {
    window.location.href = savedUrl;
  } else {
    alert("No URL saved!");
  }
}

document.getElementById("saveUrlBtn").addEventListener("click", function() {
  const currentUrl = window.location.href;
  localStorage.setItem("savedUrl", currentUrl);
  alert("URL saved!");
});

document.getElementById("clearUrlBtn").addEventListener("click", function() {
  localStorage.removeItem("savedUrl");
  alert("Saved URL cleared!");
});

document.getElementById("loadUrlBtn").addEventListener("click", function() {
  loadSavedUrl();
});

